import zeep

# Create a new client instance with the WSDL file URL
client = zeep.Client('http://example.com/insurance_service?wsdl')

def get_policy(policy_number, customer_name):
    # Prevent SOAP XML injection by using placeholders in the XML body
    policy_request = {
        'policyNumber': policy_number,
        'customerName': customer_name
    }

    try:
        response = client.service.getPolicy(**policy_request)
        return response
    except zeep.exceptions.Fault as e:
        print(f"Error: {e}")
        return None

def main():
    # Get user input for policy lookup
    policy_number = input("Enter policy number: ")
    customer_name = input("Enter customer name: ")

    # Send request to insurance service with user-provided values
    response = get_policy(policy_number, customer_name)

    if response:
        print(response)
    else:
        print("No policy found.")

if __name__ == "__main__":
    main()